if (event.getPacket() instanceof S31PacketWindowProperty) {
    S31PacketWindowProperty s31 = (S31PacketWindowProperty) event.getPacket();
    if (s31.getWindowId() == enchantTableWindowId) {
        int prop = s31.getPropertyId();
        int val = s31.getValue();
        if (prop >= 0 && prop <= 2) {
            enchantLevels[prop] = val;  // store level for each slot
        }
    }
}
// Vanilla S31PacketWindowProperty:
public class S31PacketWindowProperty implements Packet<INetHandlerPlayClient> {
    private int windowId, property, value;
    public S31PacketWindowProperty() {}
    public void processPacket(INetHandlerPlayClient h) { h.handleWindowProperty(this); }
    public int getWindowId() { return this.windowId; }
    public int getPropertyId() { return this.property; }
    public int getValue() { return this.value; }
}
